SELECT c.charge_no, c.charge_dt, c.charge_amt, m.member_no, r.region_name, cat.category_desc FROM charge AS c JOIN member AS m ON c.member_no = m.member_no JOIN region AS r ON m.region_no = r.region_no JOIN category AS cat ON c.category_no = cat.category_no WHERE (cat.category_desc = 'Meals') AND (r.region_name IN ('North American', 'South American', 'Scandanavian')) AND (strftime('%Y-%m', c.charge_dt) = '1999-08')
